        {"id": "dos-p03", "calc_type": "iv_drip_gtt", "question": "Infuse 1000 mL over 8 hr using 15 gtt/mL tubing. gtt/min?", "options": ["21 gtt/min", "31 gtt/min", "42 gtt/min", "62 gtt/min"], "correct_index": 1, "answer": "31 gtt/min", "explanation": "(1000 × 15) ÷ 480 min = 31.25 ≈ 31 gtt/min.", "trap": "Using 8 instead of 480 minutes.", "nursing_note": "Count drops full minute at bedside.", "source": s},
        {"id": "dos-p04", "calc_type": "iv_drip_ml_hr", "question": "1000 mL NS over 10 hours. Pump rate mL/hr?", "options": ["50 mL/hr", "100 mL/hr", "125 mL/hr", "250 mL/hr"], "correct_index": 1, "answer": "100 mL/hr", "explanation": "1000 ÷ 10 = 100 mL/hr.", "trap": "Dividing by minutes.", "nursing_note": "Document pump settings.", "source": s},
        {"id": "dos-p05", "calc_type": "weight_based", "question": "Order: 5 mg/kg for 44 lb child. Dose in mg? (44 lb = 20 kg)", "options": ["44 mg", "100 mg", "220 mg", "440 mg"], "correct_index": 1, "answer": "100 mg", "explanation": "20 kg × 5 mg/kg = 100 mg.", "trap": "Using 44 kg instead of 20 kg.", "nursing_note": "Verify against max single dose.", "source": s},
        {"id": "dos-p06", "calc_type": "liquid", "question": "Order: 0.5 mg. Available: 2 mg/mL. How many mL?", "options": ["0.1 mL", "0.25 mL", "0.5 mL", "1 mL"], "correct_index": 1, "answer": "0.25 mL", "explanation": "0.5 ÷ 2 = 0.25 mL — use calibrated syringe.", "trap": "Decimal placement.", "nursing_note": "Small volumes need insulin/oral syringe.", "source": s},
        {"id": "dos-p07", "calc_type": "tablet_capsule", "question": "Order: 1500 mg acetaminophen. Available: 500 mg tablets. Tablets?", "options": ["1", "2", "3", "4"], "correct_index": 2, "answer": "3 tablets", "explanation": "1500 ÷ 500 = 3.", "trap": "Exceeding 4 g/day from multiple nurses.", "nursing_note": "Check all acetaminophen sources.", "source": s},
        {"id": "dos-p08", "calc_type": "iv_drip_gtt", "question": "50 mL antibiotic over 30 min, microdrip (60 gtt/mL). gtt/min?", "options": ["50", "100", "150", "200"], "correct_index": 1, "answer": "100 gtt/min", "explanation": "(50 × 60) ÷ 30 = 100 gtt/min.", "trap": "Using 15 gtt/mL factor.", "nursing_note": "Microdrip = 60 gtt/mL always.", "source": s},
        {"id": "dos-p09", "calc_type": "weight_based", "question": "Heparin 18 units/kg bolus for 70 kg patient. Bolus units?", "options": ["560", "1260", "1800", "2520"], "correct_index": 1, "answer": "1260 units", "explanation": "70 × 18 = 1260 units.", "trap": "High-alert — double-check.", "nursing_note": "ISMP high-alert medication.", "source": s},
        {"id": "dos-p10", "calc_type": "geriatric", "question": "Standard dose 10 mg; start at 75% for older adult. Starting dose?", "options": ["2.5 mg", "5 mg", "7.5 mg", "10 mg"], "correct_index": 2, "answer": "7.5 mg", "explanation": "10 × 0.75 = 7.5 mg.", "trap": "Full adult dose in frail elderly.", "nursing_note": "Titrate slowly; fall precautions.", "source": s},
