        {"id": "dos-p13", "calc_type": "tablet_capsule", "question": "Order: 7.5 mg. Available: 2.5 mg tablets.", "options": ["1", "2", "3", "4"], "correct_index": 2, "answer": "3 tablets", "explanation": "7.5 ÷ 2.5 = 3.", "trap": "Rounding to 2 tablets underdoses.", "nursing_note": "Document partial doses clearly.", "source": s},
